"""Session, epoch, and agent derivation.

Session is the natural unit; epochs are (session_id, pid) spans within a
session, agents are subagents within a session. Helpers used by both this
module and ``processes`` live in ``_helpers``.
"""

import aiosqlite

from agentpulse.api.v2.ids import derive_epoch_id, derive_process_id
from agentpulse.api.v2.queries._helpers import (
    active_agent_states,
    agents_for_session,
    latest_hook_for_session,
)
from agentpulse.api.v2.state import compute_effective_state, derive_state


async def _latest_statusline_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> dict | None:
    cursor = await db.execute(
        """
        SELECT * FROM claude_log_statuslines
        WHERE session_id = ?
        ORDER BY received_at DESC, id DESC LIMIT 1
        """,
        (session_id,),
    )
    row = await cursor.fetchone()
    return dict(row) if row else None


# ---- session + epoch derivation ---------------------------------------------


async def _session_ids_all(db: aiosqlite.Connection) -> list[str]:
    cursor = await db.execute("""
        SELECT session_id FROM claude_log_hooks
        UNION
        SELECT session_id FROM claude_log_statuslines
        """)
    rows = await cursor.fetchall()
    return [r["session_id"] for r in rows]


async def _session_window(
    db: aiosqlite.Connection, *, session_id: str
) -> tuple[float, float] | None:
    cursor = await db.execute(
        """
        SELECT MIN(t) AS started_at, MAX(t) AS last_activity_at FROM (
            SELECT received_at AS t FROM claude_log_hooks WHERE session_id = ?
            UNION ALL
            SELECT received_at AS t FROM claude_log_statuslines WHERE session_id = ?
        )
        """,
        (session_id, session_id),
    )
    row = await cursor.fetchone()
    if row is None or row["started_at"] is None:
        return None
    return float(row["started_at"]), float(row["last_activity_at"])


async def _epochs_for_session(
    db: aiosqlite.Connection, *, session_id: str
) -> list[dict]:
    """One epoch per distinct (session_id, pid). Cwd / source_system come from
    the earliest row per pid; the schema docs treat (session_id, pid) as the
    epoch key — pid changes mid-session are the resume-into-new-process case.
    """
    cursor = await db.execute(
        """
        SELECT pid, source_system, cwd,
               MIN(received_at) AS started_at,
               MAX(received_at) AS last_activity_at,
               COUNT(*) AS event_count
        FROM claude_log_hooks
        WHERE session_id = ?
        GROUP BY pid
        ORDER BY started_at
        """,
        (session_id,),
    )
    rows = [dict(r) for r in await cursor.fetchall()]
    if not rows:
        return []

    epochs: list[dict] = []
    last_idx = len(rows) - 1
    for i, r in enumerate(rows):
        # Pull entrypoint from the first hook of this epoch (it travels with
        # each event in v2; the first row is representative).
        cursor = await db.execute(
            """
            SELECT entrypoint FROM claude_log_hooks
            WHERE session_id = ? AND pid = ?
            ORDER BY received_at, id LIMIT 1
            """,
            (session_id, r["pid"]),
        )
        ep_row = await cursor.fetchone()
        entrypoint = ep_row["entrypoint"] if ep_row else None
        # Closed epochs (any but the last by start time) get an ended_at; the
        # last open epoch leaves it null. Slice B firms this up via pid_deaths.
        ended_at = None if i == last_idx else r["last_activity_at"]
        epoch_id = derive_epoch_id(
            session_id=session_id,
            pid=r["pid"],
            source_system=r["source_system"],
            cwd=r["cwd"],
            earliest_received_at=r["started_at"],
        )
        process_id = derive_process_id(
            source_system=r["source_system"],
            pid=r["pid"],
            cwd=r["cwd"],
            earliest_received_at=r["started_at"],
        )
        epochs.append(
            {
                "epoch_id": epoch_id,
                "session_id": session_id,
                "process_id": process_id,
                "pid": r["pid"],
                "source_system": r["source_system"],
                "cwd": r["cwd"],
                "entrypoint": entrypoint,
                "started_at": r["started_at"],
                "ended_at": ended_at,
                "event_count": r["event_count"],
            }
        )
    return epochs


async def _derive_session(db: aiosqlite.Connection, *, session_id: str) -> dict | None:
    win = await _session_window(db, session_id=session_id)
    if win is None:
        return None
    started_at, last_activity_at = win

    latest_hook = await latest_hook_for_session(db, session_id=session_id)
    latest_sl = await _latest_statusline_for_session(db, session_id=session_id)

    # Current epoch identity = the (pid, source_system, cwd) of the latest
    # event source. Hook beats statusline because hooks define epoch
    # boundaries; fall back to the statusline if no hooks yet.
    current = latest_hook or latest_sl
    if current is None:
        return None
    pid = current["pid"]
    source_system = current["source_system"]
    cwd = current["cwd"]

    # Earliest received_at for this (session_id, pid) — defines the epoch's id
    # and, for processes the session belongs to, the process_id.
    cursor = await db.execute(
        """
        SELECT MIN(t) AS earliest FROM (
            SELECT received_at AS t FROM claude_log_hooks
            WHERE session_id = ? AND pid = ?
            UNION ALL
            SELECT received_at AS t FROM claude_log_statuslines
            WHERE session_id = ? AND pid = ?
        )
        """,
        (session_id, pid, session_id, pid),
    )
    row = await cursor.fetchone()
    earliest = (
        float(row["earliest"]) if row and row["earliest"] is not None else started_at
    )

    process_id = derive_process_id(
        source_system=source_system,
        pid=pid,
        cwd=cwd,
        earliest_received_at=earliest,
    )

    # ended_at: from a SessionEnd hook for this session (any pid)
    cursor = await db.execute(
        """
        SELECT received_at FROM claude_log_hooks
        WHERE session_id = ? AND event_name = 'SessionEnd'
        ORDER BY received_at DESC LIMIT 1
        """,
        (session_id,),
    )
    end_row = await cursor.fetchone()
    ended_at = float(end_row["received_at"]) if end_row else None

    last_event = (latest_hook or {}).get("event_name")
    last_tool = (latest_hook or {}).get("tool_name")
    last_event_at = (latest_hook or {}).get("received_at")

    session_state: str | None = None
    if latest_hook is not None:
        session_state = derive_state(
            latest_hook["event_name"], tool_name=latest_hook["tool_name"] or ""
        )
    agents = await agents_for_session(db, session_id=session_id)
    derived_state = compute_effective_state(session_state, active_agent_states(agents))

    cursor = await db.execute(
        "SELECT COUNT(DISTINCT pid) AS n FROM claude_log_hooks WHERE session_id = ?",
        (session_id,),
    )
    row = await cursor.fetchone()
    epoch_count = int(row["n"]) if row else 0

    return {
        "session_id": session_id,
        "platform": "claude",
        "process_id": process_id,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
        "started_at": started_at,
        "last_activity_at": last_activity_at,
        "ended_at": ended_at,
        "last_event": last_event,
        "last_tool": last_tool,
        "last_event_at": last_event_at,
        "context_used_pct": (latest_sl or {}).get("context_used_pct"),
        "context_window_size": (latest_sl or {}).get("context_window_size"),
        "model_id": (latest_sl or {}).get("model_id"),
        "model_name": (latest_sl or {}).get("model_name"),
        "agent_count": len(agents),
        "derived_state": derived_state,
        "epoch_count": epoch_count,
        "epochs": None,
        "agents": None,
    }


async def get_sessions(
    db: aiosqlite.Connection,
    *,
    active_only: bool = False,
    process_id: str | None = None,
    since: float | None = None,
) -> list[dict]:
    """List sessions derived from log tables. Ordered by last_activity_at DESC."""
    sids = await _session_ids_all(db)
    sessions: list[dict] = []
    for sid in sids:
        sess = await _derive_session(db, session_id=sid)
        if sess is None:
            continue
        if active_only and sess["ended_at"] is not None:
            continue
        if process_id is not None and sess["process_id"] != process_id:
            continue
        if since is not None and sess["last_activity_at"] < since:
            continue
        sessions.append(sess)
    sessions.sort(key=lambda s: s["last_activity_at"], reverse=True)
    return sessions


async def get_session_by_id(
    db: aiosqlite.Connection, *, session_id: str
) -> dict | None:
    """Single session by id, with epochs[] and agents[] populated."""
    sess = await _derive_session(db, session_id=session_id)
    if sess is None:
        return None
    sess["epochs"] = await _epochs_for_session(db, session_id=session_id)
    sess["agents"] = await agents_for_session(db, session_id=session_id)
    return sess
